// Парсим CSV, фильтруем reminder'ы которые надо отправить сегодня,
// рассчитываем next_date после отправки.
const raw = $('Тянем reminders CSV').item.json.data || $('Тянем reminders CSV').item.json;

function parseCsv(text) {
  if (typeof text !== 'string') text = String(text);
  const lines = text.split(/\r?\n/).filter(Boolean);
  if (!lines.length) return [];
  const splitLine = (s) => s.match(/("([^"]|"")*"|[^,]*)(,|$)/g)
    .filter(Boolean)
    .map(v => v.replace(/,$/, '').replace(/^"|"$/g, '').replace(/""/g, '"').trim());
  const headers = splitLine(lines[0]);
  return lines.slice(1).map(line => {
    const cells = splitLine(line);
    const obj = {};
    headers.forEach((h, i) => { obj[h] = cells[i] ?? ''; });
    return obj;
  });
}

const rows = parseCsv(raw);
const today = new Date().toISOString().slice(0, 10); // YYYY-MM-DD UTC

function addDays(dateStr, days) {
  const d = new Date(dateStr + 'T00:00:00Z');
  d.setUTCDate(d.getUTCDate() + days);
  return d.toISOString().slice(0, 10);
}

function nextDate(currentDate, frequency) {
  const f = String(frequency || '').trim().toLowerCase();
  if (f === 'once' || f === '') return null; // больше не повторять
  if (f === 'daily') return addDays(currentDate, 1);
  if (f === 'weekly') return addDays(currentDate, 7);
  if (f === 'monthly') return addDays(currentDate, 30);
  if (f === 'yearly') return addDays(currentDate, 365);
  // Число — раз в N дней
  const n = parseInt(f, 10);
  if (Number.isFinite(n) && n > 0) return addDays(currentDate, n);
  return null;
}

const dueToday = [];
for (const r of rows) {
  const enabled = String(r.enabled || 'TRUE').trim().toUpperCase();
  if (enabled === 'FALSE' || enabled === '0' || enabled === 'NO') continue;
  const nd = (r.next_date || '').trim();
  if (!nd) continue;
  if (nd > today) continue; // ещё не пора (включая reminder'ы из будущего)
  // Для просроченных тоже отправим (если nd < today — значит пропустили день, лучше поздно).

  const newNext = nextDate(today, r.frequency);
  const newEnabled = newNext == null ? 'FALSE' : enabled; // once → выключаем

  dueToday.push({
    json: {
      reminder_id: r.reminder_id || `${r.title}-${nd}`,
      title: r.title || '(без названия)',
      description: r.description || '',
      next_date: newNext || nd, // если once — оставляем старую (в Sheets просто enabled=FALSE)
      frequency: r.frequency || 'once',
      enabled: newEnabled,
      last_sent: today,
    },
  });
}

if (!dueToday.length) {
  // Возвращаем служебный объект чтобы дальнейшие ноды не запускались впустую
  return [{ json: { __nothing: true } }];
}
return dueToday;
